headStyle:
body {
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
            max-width: 800px;
            margin: 0 auto;
            padding: 20px;
            line-height: 1.6;
            color: #333;
        }
        h1 { color: #2c3e50; border-bottom: 2px solid #3498db; padding-bottom: 10px; }
        .meta {
            background: #ecf0f1;
            padding: 15px;
            border-radius: 5px;
            margin: 20px 0;
        }
        .meta span { margin-right: 20px; }
        h2 { color: #34495e; margin-top: 30px; }
        ul { padding-left: 20px; }
        li { margin: 8px 0; }
        ol li { margin: 15px 0; }
        .portions {
            background: #e8f6f3;
            padding: 15px;
            border-radius: 5px;
            margin: 20px 0;
        }
        .portions h3 { margin-top: 0; color: #16a085; }
        .notes {
            background: #fdebd0;
            padding: 15px;
            border-radius: 5px;
            margin: 20px 0;
        }
        .tag {
            display: inline-block;
            padding: 2px 8px;
            border-radius: 3px;
            font-size: 0.8em;
            margin-right: 5px;
            background: #d6eaf8;
            color: #2980b9;
        }
        a { color: #3498db; }
